import os
import secrets
from flask import Flask, redirect, request, session, url_for, jsonify
from authlib.integrations.flask_client import OAuth
from authlib.jose import jwt
from authlib.jose.errors import JoseError
import requests
from functools import wraps

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))
app.config['SESSION_COOKIE_SECURE'] = True
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'

OIDC_CLIENT_ID = os.environ.get('OIDC_CLIENT_ID')
OIDC_CLIENT_SECRET = os.environ.get('OIDC_CLIENT_SECRET')
OIDC_DISCOVERY_URL = os.environ.get('OIDC_DISCOVERY_URL')
OIDC_REDIRECT_URI = os.environ.get('OIDC_REDIRECT_URI')

oauth = OAuth(app)

oidc_config = None


def get_oidc_config():
    global oidc_config
    if oidc_config is None:
        response = requests.get(OIDC_DISCOVERY_URL, timeout=10)
        response.raise_for_status()
        oidc_config = response.json()
    return oidc_config


def get_jwks():
    config = get_oidc_config()
    jwks_uri = config.get('jwks_uri')
    response = requests.get(jwks_uri, timeout=10)
    response.raise_for_status()
    return response.json()


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def index():
    if 'user' in session:
        return jsonify({
            'message': 'Authenticated',
            'user': session['user']
        })
    return jsonify({'message': 'Not authenticated'})


@app.route('/login')
def login():
    config = get_oidc_config()
    authorization_endpoint = config.get('authorization_endpoint')
    
    nonce = secrets.token_urlsafe(32)
    state = secrets.token_urlsafe(32)
    
    session['nonce'] = nonce
    session['state'] = state
    
    params = {
        'client_id': OIDC_CLIENT_ID,
        'response_type': 'code',
        'scope': 'openid profile email',
        'redirect_uri': OIDC_REDIRECT_URI,
        'state': state,
        'nonce': nonce
    }
    
    auth_url = authorization_endpoint + '?' + '&'.join([f'{k}={v}' for k, v in params.items()])
    return redirect(auth_url)


@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code or not state:
        return jsonify({'error': 'Missing code or state parameter'}), 400
    
    session_state = session.pop('state', None)
    session_nonce = session.pop('nonce', None)
    
    if not session_state or state != session_state:
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    if not session_nonce:
        return jsonify({'error': 'Missing nonce in session'}), 400
    
    config = get_oidc_config()
    token_endpoint = config.get('token_endpoint')
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_REDIRECT_URI,
        'client_id': OIDC_CLIENT_ID,
        'client_secret': OIDC_CLIENT_SECRET
    }
    
    token_response = requests.post(token_endpoint, data=token_data, timeout=10)
    
    if token_response.status_code != 200:
        return jsonify({'error': 'Token exchange failed'}), 400
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    
    if not id_token:
        return jsonify({'error': 'No id_token received'}), 400
    
    try:
        jwks = get_jwks()
        
        claims = jwt.decode(id_token, jwks)
        
        claims.validate()
        
        if claims.get('nonce') != session_nonce:
            return jsonify({'error': 'Invalid nonce in id_token'}), 400
        
        if claims.get('aud') != OIDC_CLIENT_ID:
            return jsonify({'error': 'Invalid audience in id_token'}), 400
        
        issuer = config.get('issuer')
        if claims.get('iss') != issuer:
            return jsonify({'error': 'Invalid issuer in id_token'}), 400
        
        user_info = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'preferred_username': claims.get('preferred_username')
        }
        
        session['user'] = user_info
        session.permanent = True
        
        return redirect(url_for('index'))
        
    except JoseError as e:
        return jsonify({'error': 'Invalid id_token signature or format'}), 400
    except Exception as e:
        return jsonify({'error': 'Token validation failed'}), 400


